import functools

def match(pattern, key):
    pat = pattern.split('.')
    k = key.split('.')

    @functools.lru_cache(None)
    def go(i, j):
        if i == len(pat):
            return j == len(k)
        w = pat[i]
        if w == '#':
            return any(go(i + 1, j + take) for take in range(0, len(k) - j + 1))
        if j == len(k):
            return False
        if w == '*' or w == k[j]:
            return go(i + 1, j + 1)
        return False

    return go(0, 0)
